export interface ButtonProps {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  disabled?: boolean;
  onClick?: () => void;
  children: React.ReactNode;
}

export function Button({ 
  variant = 'primary', 
  size = 'md', 
  disabled = false,
  onClick,
  children 
}: ButtonProps) {
  return (
    <button 
      className={`btn btn-${variant} btn-${size}`}
      disabled={disabled}
      onClick={onClick}
    >
      {children}
    </button>
  );
}

export interface InputProps {
  label?: string;
  placeholder?: string;
  error?: string;
  type?: 'text' | 'email' | 'password' | 'number';
  value?: string;
  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

export function Input({ label, placeholder, error, type = 'text', value, onChange }: InputProps) {
  return (
    <div className="input-wrapper">
      {label && <label>{label}</label>}
      <input type={type} placeholder={placeholder} value={value} onChange={onChange} />
      {error && <span className="error">{error}</span>}
    </div>
  );
}

export interface CardProps {
  title?: string;
  footer?: React.ReactNode;
  children: React.ReactNode;
  variant?: 'default' | 'bordered' | 'elevated';
}

export function Card({ title, footer, children, variant = 'default' }: CardProps) {
  return (
    <div className={`card card-${variant}`}>
      {title && <div className="card-header">{title}</div>}
      <div className="card-body">{children}</div>
      {footer && <div className="card-footer">{footer}</div>}
    </div>
  );
}

export interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title?: string;
  children: React.ReactNode;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

export function Modal({ isOpen, onClose, title, children, size = 'md' }: ModalProps) {
  if (!isOpen) return null;
  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div className={`modal modal-${size}`} onClick={(e) => e.stopPropagation()}>
        {title && <div className="modal-header">{title}</div>}
        <div className="modal-body">{children}</div>
      </div>
    </div>
  );
}

export interface DropdownProps {
  options: Array<{ value: string; label: string }>;
  value?: string;
  onChange?: (value: string) => void;
  placeholder?: string;
  disabled?: boolean;
}

export function Dropdown({ options, value, onChange, placeholder = 'Select...', disabled = false }: DropdownProps) {
  return (
    <select value={value} onChange={(e) => onChange?.(e.target.value)} disabled={disabled}>
      <option value="">{placeholder}</option>
      {options.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
    </select>
  );
}
